public boolean sameEnds(int[] nums, int n) {
    if (n == 0) {
        return true;
    }
    int[] start = new int[n];
    int[] end = new int[n];
    System.arraycopy(nums, 0, start, 0, Math.min(nums.length, n));
    System.arraycopy(nums, nums.length - n, end, 0, n);
    for (int i = 0; i < n; i++) {
        if (start[i] != end[i]) {
            return false;
        }
    }
    return true;
}

