public int countClumps(int[] nums) {
    int count = 0;
    boolean isClump = false;

    for (int i = 1; i < nums.length; i++) {
        if (nums[i] == nums[i - 1]) {
            if (!isClump) {
                count++;
                isClump = true;
            }
        } else {
            isClump = false;
        }
    }

    return count;
}

