Code:
public boolean canBalance(int[] nums) {
    int leftSum = 0;
    int rightSum = 0;
    for (int i = 0; i < nums.length; i++) {
        rightSum += nums[i];
    }
    for (int i = 0; i < nums.length; i++) {
        rightSum -= nums[i];
        if (leftSum == rightSum) {
            return true;
        }
        leftSum += nums[i];
    }
    return false;
}

public boolean isEverywhere(int[] nums, int val) {
    if (nums.length == 0 || nums.length == 1) {
        return true;
    }

    for (int i = 0; i < nums.length - 1; i++) {
        if (nums[i] != val && nums[i + 1] != val) {
            return false;
        }
    }
    return true;
}

public int caughtSpeeding(int speed, boolean isBirthday) {
    int speedLimit = 60;
    if (isBirthday) {
        speedLimit += 5;
    }
    if (speed <= speedLimit) {
        return 0;
    } else if (speed <= 80) {
        return 1;
    } else {
        return 2;
    }
}
